import { Component, Prop, h } from '@stencil/core';

/**
 * Accent icons act as entry points to additional information or content. They add color and life to the interface while visually expressing our product offerings.
 */
@Component({
  tag: "kds-accent-icon",
  styleUrl: "kds-accent-icon.css",
  shadow: false
})
export class KdsAccentIcon {
  /** @Private render prop used to set the img src */
  @Prop() readonly src: string;
  /** KDS designated sizes. */
  @Prop() readonly size: "s" | "m" | "l" | "xl" = "s";
  /** Defines alternative text of an image. */
  @Prop() readonly alt: string;

  render() {
    return (
      <img
        class={{
          "kds-AccentIcon": true,
          "kds-AccentIcon--small": this.size === "s",
          "kds-AccentIcon--medium": this.size === "m",
          "kds-AccentIcon--large": this.size === "l",
          "kds-AccentIcon--extraLarge": this.size === "xl"
        }}
        src={this.src}
        alt={this.alt || ""}
      />
    );
  }
}
